mapper.select:

where f.del_flag = '0'
AND f.file_name like concat('%', #{fileName}, '%')
AND f.file_category = #{fileCategory}
AND f.access_scope = #{accessScope}
AND f.upload_user_id = #{uploadUserId}
AND f.status = #{status}
AND f.file_suffix = #{fileSuffix}

    AND date_format(f.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


    AND date_format(f.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')

order by f.create_time desc


where f.del_flag = '0'
AND f.file_name like concat('%', #{file.fileName}, '%')
AND f.file_category = #{file.fileCategory}
AND f.access_scope = #{file.accessScope}
AND f.upload_user_id = #{file.uploadUserId}
AND f.status = #{file.status}
AND f.file_suffix = #{file.fileSuffix}

    AND date_format(f.create_time,'%Y%m%d') >= date_format(#{file.params.beginTime},'%Y%m%d')


    AND date_format(f.create_time,'%Y%m%d') <= date_format(#{file.params.endTime},'%Y%m%d')

order by f.create_time desc

