update campus_shared_file
file_name = #{fileName}, original_name = #{originalName}, file_url = #{fileUrl}, file_path = #{filePath}, file_suffix = #{fileSuffix}, file_size = #{fileSize}, file_category = #{fileCategory}, access_scope = #{accessScope}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
